import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Ensure that only up to the length of userInput or buffer size is copied to buffer
        int numCharsToCopy = Math.min(userInput.length(), buffer.length);
        userInput.getChars(0, numCharsToCopy, buffer, 0);

        // Iterate up to the number of characters actually copied
        for (int i = 0; i < numCharsToCopy; i++) {
            System.out.print(buffer[i]);
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
